import{_ as c,C as u,o as i,c as p,a2 as r,b as n,w as a,a as t,E as l,a3 as s,j as d}from"./chunks/framework.Bj6f68Cg.js";const C=JSON.parse('{"title":"AI Gateway Infra Demo","description":"","frontmatter":{},"headers":[],"relativePath":"projects/ai-gateway-infra-demo.md","filePath":"projects/ai-gateway-infra-demo.md"}'),h={name:"projects/ai-gateway-infra-demo.md"};function L(m,e,g,b,k,y){const o=u("Mermaid");return i(),p("div",null,[e[2]||(e[2]=r('<h1 id="ai-gateway-infra-demo" tabindex="-1">AI Gateway Infra Demo <a class="header-anchor" href="#ai-gateway-infra-demo" aria-label="Permalink to &quot;AI Gateway Infra Demo&quot;">​</a></h1><p>LiteLLM을 중심으로 vLLM과 MLX 추론 Endpoint를 하나의 OpenAI-compatible API로 통합하는 Multi-node Inference Routing 템플릿입니다.</p><h2 id="📌-status-repository" tabindex="-1">📌 Status &amp; Repository <a class="header-anchor" href="#📌-status-repository" aria-label="Permalink to &quot;📌 Status &amp; Repository&quot;">​</a></h2><ul><li><strong>상태</strong>: <code>Prototype</code></li><li><strong>저장소 주소</strong>: <a href="https://github.com/devcy0922/ai-gateway-infra-demo" target="_blank" rel="noreferrer">GitHub (devcy0922/ai-gateway-infra-demo)</a></li><li><strong>라이선스</strong>: MIT</li><li><strong>주요 구성</strong>: Docker Compose, LiteLLM, Promtail</li></ul><hr><h2 id="_1-problem" tabindex="-1">1. Problem <a class="header-anchor" href="#_1-problem" aria-label="Permalink to &quot;1. Problem&quot;">​</a></h2><p>GPU 추론 노드와 로컬 추론 노드가 서로 다른 Model ID와 Endpoint를 제공하면 Client가 Provider별 연결 정보와 장애 처리 로직을 알아야 합니다. 특정 노드의 지연이나 장애가 전체 애플리케이션으로 전파되지 않도록 공통 Routing과 Fallback 경계가 필요합니다.</p><h2 id="_2-why-i-built-it" tabindex="-1">2. Why I Built It <a class="header-anchor" href="#_2-why-i-built-it" aria-label="Permalink to &quot;2. Why I Built It&quot;">​</a></h2><p>LiteLLM의 Provider Adapter와 Router를 이용해 <code>auto</code>, <code>fast</code>, <code>thinking</code>, <code>embedding</code> 같은 안정적인 Model Alias를 제공하고, vLLM과 MLX의 차이를 Client에서 숨기는 구성을 검증하기 위해 만들었습니다.</p><h2 id="_3-scope" tabindex="-1">3. Scope <a class="header-anchor" href="#_3-scope" aria-label="Permalink to &quot;3. Scope&quot;">​</a></h2><ul><li>vLLM과 MLX를 OpenAI-compatible Endpoint로 통합</li><li>Model Alias별 Timeout과 Token 상한 설정</li><li>Least-busy Routing, Retry, Fast/Thinking Fallback 선언</li><li>PostgreSQL 기반 LiteLLM Spend Log 연결 설정</li><li>Promtail을 이용한 Container/Audit Log의 Loki 전송</li><li>Optional Prompt Enricher와 Workflow Component 연결점</li></ul><hr><h2 id="_4-architecture" tabindex="-1">4. Architecture <a class="header-anchor" href="#_4-architecture" aria-label="Permalink to &quot;4. Architecture&quot;">​</a></h2>',13)),(i(),n(s,null,{default:a(()=>[l(o,{id:"mermaid-83",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20Client%5B%22Client%20%2F%20Application%22%5D%20--%3E%20Front%5B%22Front%20Policy%20Gateway%22%5D%0A%20%20%20%20Front%20--%3E%20LiteLLM%5B%22LiteLLM%20Router%22%5D%0A%20%20%20%20LiteLLM%20--%3E%7C%22fast%20%C2%B7%20thinking%22%7C%20vLLM%5B%22vLLM%20GPU%20Endpoint%22%5D%0A%20%20%20%20LiteLLM%20-.%20%22Fallback%22%20.-%3E%20MLX%5B%22MLX%20Endpoint%22%5D%0A%20%20%20%20LiteLLM%20--%3E%7C%22embedding%22%7C%20Embed%5B%22Embedding%20Endpoint%22%5D%0A%20%20%20%20LiteLLM%20--%3E%20DB%5B%22PostgreSQL%20Spend%20Log%22%5D%0A%20%20%20%20Logs%5B%22Container%20%26%20Audit%20Logs%22%5D%20--%3E%20Promtail%5B%22Promtail%22%5D%0A%20%20%20%20Promtail%20--%3E%20Loki%5B%22Loki%20%2F%20Grafana%22%5D%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[t(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=d("h2",{id:"_5-request-flow",tabindex:"-1"},[t("5. Request Flow "),d("a",{class:"header-anchor",href:"#_5-request-flow","aria-label":'Permalink to "5. Request Flow"'},"​")],-1)),(i(),n(s,null,{default:a(()=>[l(o,{id:"mermaid-87",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20autonumber%0A%20%20%20%20participant%20Client%0A%20%20%20%20participant%20Gateway%20as%20Front%20Gateway%0A%20%20%20%20participant%20Router%20as%20LiteLLM%0A%20%20%20%20participant%20GPU%20as%20vLLM%0A%20%20%20%20participant%20Local%20as%20MLX%0A%20%20%20%20Client-%3E%3EGateway%3A%20model%3Dfast%2C%20OpenAI-compatible%20request%0A%20%20%20%20Gateway-%3E%3ERouter%3A%20%EC%9D%B8%EC%A6%9D%EB%90%9C%20%EC%9A%94%EC%B2%AD%20%EC%A0%84%EB%8B%AC%0A%20%20%20%20Router-%3E%3EGPU%3A%20Least-busy%20route%0A%20%20%20%20alt%20Primary%20%EC%8B%A4%ED%8C%A8%0A%20%20%20%20%20%20%20%20Router-%3E%3EGPU%3A%20Retry%0A%20%20%20%20%20%20%20%20Router-%3E%3ELocal%3A%20Configured%20fallback%0A%20%20%20%20%20%20%20%20Local--%3E%3ERouter%3A%20Response%0A%20%20%20%20else%20Primary%20%EC%A0%95%EC%83%81%0A%20%20%20%20%20%20%20%20GPU--%3E%3ERouter%3A%20Response%0A%20%20%20%20end%0A%20%20%20%20Router--%3E%3EGateway%3A%20Unified%20response%0A%20%20%20%20Gateway--%3E%3EClient%3A%20OpenAI-compatible%20response%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[t(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=r(`<h2 id="_6-key-design-decisions" tabindex="-1">6. Key Design Decisions <a class="header-anchor" href="#_6-key-design-decisions" aria-label="Permalink to &quot;6. Key Design Decisions&quot;">​</a></h2><ul><li><strong>Client와 Provider 분리</strong>: Client는 실제 Model ID나 Node 주소가 아니라 <code>fast</code>, <code>thinking</code> 같은 안정적인 Alias를 사용합니다.</li><li><strong>설정 기반 복구 경로</strong>: Retry 횟수, Timeout과 Fallback Mapping을 LiteLLM Config에 선언해 애플리케이션 코드에서 분리합니다.</li><li><strong>로그 수집 분리</strong>: Promtail이 Runtime Log를 Loki로 전달하고 추론 서비스는 로그 Backend의 구현을 알지 않도록 구성합니다.</li></ul><h2 id="_7-security-considerations" tabindex="-1">7. Security Considerations <a class="header-anchor" href="#_7-security-considerations" aria-label="Permalink to &quot;7. Security Considerations&quot;">​</a></h2><ul><li>실제 API Key, Database URL과 Node 주소는 <code>.env</code>에만 두고 저장소에는 <code>.env.example</code>만 제공합니다.</li><li>LiteLLM은 내부 Master Key를 요구하고 외부 Client 인증과 세부 정책은 Front Gateway 책임으로 분리합니다.</li><li>Prompt Enricher의 Soft Check를 보안 경계로 과장하지 않으며 최종 차단 정책은 별도 Gateway에서 수행해야 합니다.</li></ul><h2 id="_8-observability" tabindex="-1">8. Observability <a class="header-anchor" href="#_8-observability" aria-label="Permalink to &quot;8. Observability&quot;">​</a></h2><ul><li>LiteLLM Request/Spend Log를 PostgreSQL에 저장할 수 있도록 구성합니다.</li><li>Promtail은 Docker stdout과 Mount된 Audit Log를 Loki로 전송합니다.</li><li>이 저장소는 관측 Backend 자체보다 수집과 Routing 연결 설정을 제공하는 Template입니다.</li></ul><h2 id="_9-technology-stack" tabindex="-1">9. Technology Stack <a class="header-anchor" href="#_9-technology-stack" aria-label="Permalink to &quot;9. Technology Stack&quot;">​</a></h2><ul><li><strong>Router</strong>: LiteLLM Proxy</li><li><strong>Inference</strong>: vLLM, MLX, OpenAI-compatible Endpoints</li><li><strong>Logs</strong>: Promtail, Loki, Grafana</li><li><strong>Runtime Definition</strong>: Docker Compose</li></ul><h2 id="_10-running-locally" tabindex="-1">10. Running Locally <a class="header-anchor" href="#_10-running-locally" aria-label="Permalink to &quot;10. Running Locally&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span></span></code></pre></div><p>구성 검증 후 실제 환경의 vLLM, MLX, PostgreSQL, Loki Endpoint를 연결합니다. 공개 저장소에 포함되지 않은 Optional Build Context는 해당 Profile 또는 Service를 제외하고 검증해야 합니다.</p><h2 id="_11-current-limitations" tabindex="-1">11. Current Limitations <a class="header-anchor" href="#_11-current-limitations" aria-label="Permalink to &quot;11. Current Limitations&quot;">​</a></h2><ul><li>현재 저장소는 운영 Cluster 전체가 아니라 Routing과 Log Collection 구성을 보여주는 Prototype입니다.</li><li>일부 Optional Component의 Source/Build Context는 공개 저장소에 포함되지 않습니다.</li><li>Immutable Image Tag, 자동 장애 주입 Test와 SLO는 아직 제공하지 않습니다.</li></ul><h2 id="_12-next-steps" tabindex="-1">12. Next Steps <a class="header-anchor" href="#_12-next-steps" aria-label="Permalink to &quot;12. Next Steps&quot;">​</a></h2><ul><li>Mock Upstream 기반 Routing/Fallback CI 추가</li><li>Image Version 고정과 SBOM·Vulnerability Scan 추가</li><li>Failover Time, Error Rate와 p95 Latency를 측정하는 재현 가능한 Failure Drill 추가</li></ul>`,15))])}const f=c(h,[["render",L]]);export{C as __pageData,f as default};
